  }), mdx("p", null, "\uB178\uAC00\uB2E4 \uC77C\uB2F9 10\uB9CC\uC6D0\uC774\uB780?\n\uC5F0\uBD09 4\uCC9C\uC774\uBA74 \uC138\uAE08\uB5BC\uACE0 \uC8FC\uB9D0\uC81C\uC678 \uC77C\uB2F9 \uC57D 14\uB9CC\uC6D0.. \uB9E4\uCD9C 42~50\uB9CC\uC6D0\uC758 \uC601\uD5A5\uB825\uC774\uB780?"), mdx("p", null, "\uC798 \uB9E4\uCE6D\uC774 \uC548\uB418\uB2C8\uAE4C \uC2DD\uC0AC\uB97C \uBA39\uB294\uB2E4\uACE0 \uCE58\uACE0\n\uC801\uB2F9\uD55C \uC2DD\uC0AC\uB97C \uCE58\uD0A8 \uD55C\uB9C8\uB9AC 2\uB9CC\uC6D0\uC5D0 \uBA39\uC5C8\uB2E4\uACE0 \uD55C\uB2E4\uBA74?\n\uB178\uAC00\uB2E4\uB97C \uD558\uBA74 \uBD80\uAC00\uAC00\uCE58\uB97C \uCE58\uD0A8 \uD55C\uB9C8\uB9AC\uC758 5\uBC30\uB97C \uCC3D\uCD9C\uD588\uB2E4... 5\uB07C\uB2C8\uB97C \uCE58\uD0A8\uC73C\uB85C \uC12D\uCDE8\uD560\uC218 \uC788\uB2E4...\n\uB2ED\uC744 \uD0A4\uC6CC\uC11C \uD314\uACE0, \uADF8\uAC78 \uAC00\uACF5\uD558\uACE0, \uC720\uD1B5\uD558\uACE0, \uB808\uC2DC\uD53C \uC9C0\uC2DD\uC7AC\uC0B0 \uC218\uC218\uB8CC\uB97C \uB0B4\uACE0, \uAE30\uB984\uC5D0 \uD280\uACA8\uC11C \uD314\uBA74 \uD55C\uB9C8\uB9AC\uB2F9 2\uB9CC\uC6D0\uC758 \uAC00\uCE58\uAC00 \uC0DD\uAE34\uB2E4? \uB098\uB294 \uC5BC\uB9C8\uB97C \uB0A8\uAE30\uB098?\n4\uCC9C\uC6D0\uC815\uB3C4 \uB0A8\uB294\uB2E4\uACE0 \uD568 \uBCF8\uC0AC\uB3C4 \uD55C 4\uCC9C\uC6D0...?\n\uCD94\uAC00\uB85C \uC778\uAC74\uBE44, \uC6D4\uC138 \uB4F1\uC744 \uC81C\uC678\uD558\uBA74 \uC810\uC8FC \uC21C\uC218\uC775\uC774 2\uCC9C\uC6D0, 5\uB9C8\uB9AC\uC529 10\uC2DC\uAC04 \uD558\uB8E8 100\uB9CC\uC6D0, 20\uC77C \uC77C\uD558\uBA74 \uC6D4 2\uCC9C, \uC5EC\uAE30\uC5D0 10\uD37C\uC13C\uD2B8\uBA74 \uC57D \uC6D4 200...\n\uC774 \uC0AC\uB78C\uC740 \uC2E4\uC81C \uB178\uB3D9\uC73C\uB85C \uC2DC\uAC04\uB2F9 1\uB9CC\uC6D0\uC744 \uBC8C\uACE0 \uC989 \uC2DC\uAE09\uC774 \uB9CC\uC6D0\uC774\uACE0 \uB9E4\uCD9C\uC740 \uADF8 10\uBC30\uB97C \uB9CC\uB4EC. \uBB3C\uB860 \uADF8\uB9CC\uD07C \uC911\uAC04\uC5D0 \uBE60\uC9C0\uB294\uAC8C \uB9CE\uACE0 \uBCF5\uC7A1\uD558\uAE30 \uB54C\uBB38\uC774\uC9C0\uB9CC\n\uB300\uB7B5 \uC2E0\uCCB4 \uB178\uB3D9 \uAC15\uB3C4\uB85C\uB9CC \uC77C\uC744 \uD558\uBA74 \uD558\uB8E8 \uC77C\uB2F9 10\uB9CC\uC6D0 \uC815\uB3C4\uAC00 \uB098\uC624\uAE34 \uD558\uB124. "), mdx("p", null, "\uADF8\uB7FC \uB0B4\uAC00 \uC778\uB0B4\uD558\uACE0 \uD1B5\uCC30\uD558\uACE0 \uD22C\uC790\uD55C \uC2DC\uAC04\uACFC \uB178\uB825, \uC77C\uC815 \uC7AC\uB2A5 \uBE44\uC6A9\uACFC \uD76C\uADC0\uC131\uC744 \uACE0\uB824\uD588\uC744\uB54C\n50\uD37C\uC13C\uD2B8 \uB354 \uBC1B\uB294\uAC8C \uB2F9\uC704\uC131\uC774 \uC0DD\uAE30\uB098?\n\uC0AC\uB78C \uD558\uB098\uAC00 \uC77C\uD558\uBA74 \uADF8\uB0E5 \uC0AC\uB78C \uD558\uB098\uC9C0\uB9CC \uADF8\uAC8C 1.5\uC778\uBD84\uC744 \uD574\uB0BC\uC218 \uC788\uB2E4\uBA74 \uC0DD\uC0B0\uC131\uC774 \uC62C\uB77C\uAC00\uACE0 \uADF8\uB9CC\uD07C \uAE30\uC5EC\uD55C \uC148\uC774 \uB418\uB2C8\uAE4C \uD55C\uC0AC\uB78C \uBD84 \uBCF4\uB2E4\uB294 \uB118\uCE58\uACE0 \uB450 \uC0AC\uB78C \uBD84 \uBCF4\uB2E4\uB294 \uBAA8\uC790\uB77C\uB2E4\uBA74 \uC560\uB9E4\uD55C \uCF54\uB4DC \uB450\uC904\uC774 \uB0B4\uAC00 \uC9E0 \uACE0\uAE09 \uCF54\uB4DC 1\uC904\uBCF4\uB2E4\uB294 \uB0AB\uC9C0\uB9CC \uC560\uB9E4\uD55C 1.5\uC904 \uBCF4\uB2E4\uB294 \uB0AB\uB2E4\uBA74 \uADF8 \uC801\uC808\uD568\uC744 \uC5B4\uB5BB\uAC8C \uACC4\uC0B0\uD574\uC57C\uD558\uB098\n10\uD37C\uC13C\uD2B8\uBCF4\uB2E4\uB294 \uCEE4\uC57C \uC804\uD658\uBE44\uC6A9\uC774\uB098 \uC774\uD6C4 \uC218\uC775\uC131, \uB9AC\uD134\uC744 \uACE0\uB824\uD574\uC57C\uD560\uD14C\uB2C8 .. \uCD5C\uC18C 20\uD37C\uC13C\uD2B8 \uC774\uC0C1... \uB0B4\uAC00 \uADF8\uB0E5 \uB450\uBC88\uC77C\uC744 \uD558\uB294\uAC8C \uD55C\uC0AC\uB78C\uC774 \uC138\uBC88 \uD558\uB294\uAC70\uB791 \uAC19\uC744\uAE4C? \uD558\uB8E8 \uC77C\uD558\uACE0 \uB2E4\uC74C\uB0A0 \uC624\uD6C4\uC5D0 \uACB0\uACFC\uB97C \uB0BC\uC218\uC788\uC73C\uBA74 \uC774\uD2C0 \uC77C\uD558\uACE0 \uADF8 \uB2E4\uC74C\uB0A0 \uC624\uC804\uC5D0 \uB0B4\uB294\uAC70\uBCF4\uB2E4 \uB0AB\uC9C0? \uADFC\uB370 \uC815\uB9D0 \uADF8\uC815\uB3C4 \uD6A8\uACFC\uAC00 \uB098\uB294\uAC78\uAE4C?"), mdx("p", null, "\uB0B4 \uC778\uAC74\uBE44\uC640 \uADF8\uAC78 \uC5BC\uB9C8\uC5D0 \uD314\uC9C0...\n\uADF8\uB7FC \uADF8\uB807\uAC8C 1.5\uBC30\uAC00 \uD569\uB2F9\uD558\uB2E4\uACE0 \uAC00\uC815\uD558\uACE0, \uADF8 \uC81C\uD488\uC758 \uAC00\uCE58\uB098 \uC601\uD5A5\uB825\uC774 \uB0B4\uAC00 \uB178\uB825\uD558\uACE0 \uBD80\uC740 1.5\uBC30\uC758 \uB178\uB825\uC774 4.5\uBC30\uB85C \uBD88\uC5B4\uB0A0\uC218 \uC788\uB294\uC9C0? \uC815\uD655\uD788\uB294 3\uBC30 \uC815\uB3C4\uB9CC \uAE30\uC5EC\uD558\uBA74 \uB418\uC9C0. \uB0B4 \uBAAB\uC744 \uC81C\uC678\uD558\uACE0."), mdx("p", null, "\uD504\uB79C\uCC28\uC774\uC988\uB294 \uC9C1\uC811 \uAC00\uAC8C\uB97C \uD558\uC9C0\uC54A\uACE0 \uC9C1\uC6D0\uB300\uC2E0 \uC790\uC601\uC5C5\uC790\uB97C \uACE0\uC6A9\uD558\uB294 \uC774\uC720\uAC00 \uC790\uC728\uC131\uC5D0 \uB530\uB978 \uC774\uC775\uB960 \uADF9\uB300\uD654\uB098 \uB0B4 \uC774\uC775\uC758 \uBC18\uC744 \uC8FC\uB354\uB77C\uB3C4 \uC804\uCCB4 \uB9E4\uCD9C\uC744 \uB9CC\uB4DC\uB294\uAC74...  \uD63C\uC790 \uC5F4\uC2EC\uD788 \uD574\uC11C 2\uB97C \uB9CC\uB4E4\uACE0 2\uB97C \uCC59\uAE30\uAE30\uBCF4\uB2E4 \uC5EC\uB7FF\uC744 \uB9AC\uB4DC\uD574\uC11C 4\uBA85\uC774\uC11C 10\uC744 \uB9CC\uB4E4\uACE0 2\uB97C \uB098\uB220\uC8FC\uACE0 4\uB97C \uAC00\uC838\uAC00\uBA74 \uB0AB\uACA0\uC9C0."), mdx("p", null, "\uACB0\uAD6D \uD300\uC791\uC5C5\uC5D0\uB294 \uC2DC\uB108\uC9C0\uB77C\uB358\uAC00 \uC870\uC9C1\uC801\uD611\uC5C5\uC5D0 \uB530\uB978 \uAC00\uCE58\uAC00 \uB354\uC6B1 \uBD80\uAC00\uB418\uACE0 \uADF8\uB7F0 \uCEE4\uBBA4\uB2C8\uCF00\uC774\uC158 \uBE44\uC6A9\uC774\uB098 \uCC3D\uCD9C\uAC00\uCE58\uAE4C\uC9C0\uB3C4 \uACE0\uB824\uB420\uC218 \uC788\uB294 \uC911\uC694\uD55C \uC601\uC5C5\uC801 \uAC00\uCE58\uB098 \uB2A5\uB825\uC774 \uB41C\uB2E4\uB294...\n4\uBA85\uC774\uB77C \uAC00\uC815\uD558\uACE0 \uAC01\uC790 2\uC529 \uB9CC\uB4E4\uC5B4\uB0B4\uBA74\uC11C \uBD80\uAC00\uC801\uC778 2\uAC00 \uCD94\uAC00\uB85C \uC0DD\uAE34\uB2E4\uBA74 \uB098\uB294 \uAE30\uC5EC\uD588\uB2E4\uACE0 \uBCFC\uC218 \uC788\uC9C0\uC54A\uC744\uAE4C?\n\uACB0\uAD6D \uADF8 \uBD80\uAC00\uC801\uC778 2\uB97C \uB9CC\uB4E4\uC5B4\uB0BC\uC218 \uC788\uB294 \uC7A0\uC7AC \uAC00\uCE58\uAC00 \uC788\uB290\uB0D0\uAC00 \uC9C1\uC6D0 \uCC44\uC6A9\uC758 \uAC00\uC7A5 \uD575\uC2EC\uC801\uC778 \uB0B4\uC6A9\uC774\uC790 \uD3C9\uAC00 \uB300\uC0C1, \uD310\uB2E8 \uAE30\uC900\uC774 \uB418\uB294\uAC74?\n\uADF8\uAC8C \uC774\uC81C \uD68C\uC0AC\uAC00 \uC6D0\uD558\uB294 \uBE44\uC804, \uC6B0\uB300\uC0AC\uD56D\uC774 \uB418\uB294\uAC70\uACA0\uB2E4."));
